def cards(items): return ''.join(f'<div class="rb-card"><strong>{html.escape(a)}</strong><span>{html.escape(b)}</span></div>' for a,b in items)
def related(current): return ''.join(f'<a href="{u}"'+(' aria-current="page"' if u.endswith(current) else '')+f'><strong>{html.escape(t)}</strong><span>{html.escape(d)}</span></a>' for t,u,d in COMMON_RELATED)
def render(t):
 toc=''.join(f'<a href="#{i}">{html.escape(h)}</a>' for i,h,_ in t['sections'])+'<a href="#faq">FAQ</a><a href="#related">관련 글</a>'
 body=''.join(f'<section class="rb-section" id="{i}"><h2>{html.escape(h)}</h2>'+''.join(f'<p>{html.escape(p)}</p>' for p in ps)+'</section>' for i,h,ps in t['sections'])
 faq=''.join(f'<details><summary>{html.escape(q)}</summary><p>{html.escape(a)}</p></details>' for q,a in t['faq'])
