def main(apply=False):
 if OUT.parent.exists(): shutil.rmtree(OUT.parent)
 OUT.mkdir(parents=True)
 report=[]
 for t in TOPICS:
  text=render(t); (OUT/t['file']).write_text(text,encoding='utf-8')
  if apply:
   (ROOT/'articles'/t['file']).write_text(text,encoding='utf-8')
  report.append(dict(file=t['file'],h1=len(re.findall(r'<h1\b',text)),hero=text.count('data-factory-hero="true"'),brain=text.count('savingio-brain-navigation.js?v=12'),calculator=('rb-calc' in text),related=text.count('class="rb-related"')))
 (OUT.parent/'report.json').write_text(json.dumps(report,ensure_ascii=False,indent=2)+'\n',encoding='utf-8')
 print(json.dumps(report,ensure_ascii=False,indent=2))
if __name__=='__main__':
 parser=argparse.ArgumentParser(); parser.add_argument('--apply',action='store_true'); args=parser.parse_args(); main(args.apply)
